1	// Package validator enforces tier rules and the hard-block list.
2	package validator
3	
4	import (
5		"errors"
6		"regexp"
7		"strings"
8	)
9	
10	// Tier constants mirror the three permission levels.
11	const (
12		TierRead    = 1 // read-only: auto-executes, no approval needed
13		TierService = 2 // service ops: restart packages/containers; approval required
14		TierFile    = 3 // file ops: touches user data volumes; approval required
15	)
16	
17	// hardBlocked is a list of patterns that are NEVER permitted regardless of tier.
18	// These could brick the NAS, destroy data, modify the OS, or lock out admins.
19	var hardBlocked = []*regexp.Regexp{
20		// Disk destruction
21		regexp.MustCompile(`(?i)\bmkfs\b`),
22		regexp.MustCompile(`(?i)\bfdisk\b`),
23		regexp.MustCompile(`(?i)\bparted\b`),
24		regexp.MustCompile(`(?i)\bmdadm\s+--fail\b`),
25		regexp.MustCompile(`(?i)\bdd\s+if=`),
26		regexp.MustCompile(`(?i)\bwipefs\b`),
27		// Root filesystem destruction
28		regexp.MustCompile(`(?i)\brm\s+(-\S*f\S*\s+)*/?$`),
29		regexp.MustCompile(`(?i)\brm\s+(-\S+\s+)*/boot\b`),
30		regexp.MustCompile(`(?i)\brm\s+(-\S+\s+)*/usr\b`),
31		regexp.MustCompile(`(?i)\brm\s+(-\S+\s+)*/etc\b`),
32		// System software — DSM/Synology binaries must not be modified
33		regexp.MustCompile(`(?i)(>|>>|tee)\s+/usr/syno`),
34		regexp.MustCompile(`(?i)\bsynopkg\s+(install|uninstall|remove)\b`),
35		// Firmware / kernel
36		regexp.MustCompile(`(?i)\bflash_eraseall\b`),
37		regexp.MustCompile(`(?i)\bnandwrite\b`),
38		regexp.MustCompile(`(?i)\binsmod\b`),
39		regexp.MustCompile(`(?i)\brmmod\b`),
40		// Ptrace code-injection vectors — blocked even though CAP_SYS_PTRACE is granted.
41		// strace (read-only syscall tracing) remains unblocked and tier-1 executable.
42		// gdb/lldb can call arbitrary functions in a traced process via "call system(...)".
43		regexp.MustCompile(`(?i)\bgdb\b`),
44		regexp.MustCompile(`(?i)\blldb\b`),
45		// Destructive hdparm operations — security erase, standby/sleep, write-cache toggle.
46		// Safe read flags (-I device identity, -t throughput test) remain unblocked.
47		regexp.MustCompile(`(?i)\bhdparm\b.*--security-`),
48		regexp.MustCompile(`(?i)\bhdparm\b.*\s-[yYW]\b`),
49		// dd writing directly to a device or /proc — would be a memory/disk write vector.
50		// dd if= is already blocked above; this adds the of= form.
51		regexp.MustCompile(`(?i)\bdd\b.*\bof=/dev/`),
52		regexp.MustCompile(`(?i)\bdd\b.*\bof=/proc/`),
53		// User account manipulation
54		regexp.MustCompile(`(?i)\buseradd\b`),
55		regexp.MustCompile(`(?i)\buserdel\b`),
56		regexp.MustCompile(`(?i)\busermod\b`),
57		regexp.MustCompile(`(?i)\bgroupadd\b`),
58		regexp.MustCompile(`(?i)\bgroupdel\b`),
59		regexp.MustCompile(`(?i)\bpasswd\s+\S`), // passwd <user> but not plain passwd
60		// NAS shutdown (use DSM UI for planned maintenance)
61		regexp.MustCompile(`(?i)\bshutdown\b`),
62		regexp.MustCompile(`(?i)\breboot\b`),
63		regexp.MustCompile(`(?i)\bpoweroff\b`),
64		regexp.MustCompile(`(?i)\bhalt\b`),
65		regexp.MustCompile(`(?i)\bsystemctl\s+(poweroff|halt|reboot)\b`),
66		// Package manager (apt/opkg/pip global installs)
67		regexp.MustCompile(`(?i)\bapt(-get)?\s+(install|remove|purge)\b`),
68		regexp.MustCompile(`(?i)\bopkg\s+(install|remove)\b`),
69		regexp.MustCompile(`(?i)\bpip\s+install\b`),
70		regexp.MustCompile(`(?i)\bnpm\s+install\s+-g\b`),
71		// Recursive grep/find on Synology internal data stores.
72		// These directories contain millions of opaque file objects; a recursive
73		// grep never returns useful results and will thrash disk I/O for days.
74		// Use targeted find -maxdepth or a database query instead.
75		regexp.MustCompile(`(?i)\bgrep\b.*-[a-zA-Z]*[rR][a-zA-Z]*\s.*(@synologydrive|@SynologyDriveShareSync|/var/packages/SynologyDrive)`),
76		regexp.MustCompile(`(?i)\bgrep\b.*(@synologydrive|@SynologyDriveShareSync|/var/packages/SynologyDrive).*-[a-zA-Z]*[rR]`),
77		// Mount destructive operations
78		regexp.MustCompile(`(?i)\bumount\s+/volume`),
79		regexp.MustCompile(`(?i)\bmount\s+.*--bind.*/volume`),
80		// Docker socket is effectively host-level control, so only a tiny allowlist
81		// of monitor-stack actions may use it. Everything else is blocked outright.
82		regexp.MustCompile(`(?i)\bdocker\s+(run|create|cp|plugin|network|volume|context|swarm|stack|builder|buildx)\b`),
83	}
84	
85	// safeRedirectRe strips redirect forms that are not writes:
86	// - N>/dev/null or >>/dev/null  (discard output)
87	// - N>&M                        (fd-to-fd, e.g. 2>&1)
88	var (
89		safeRedirectRe   = regexp.MustCompile(`\d*>>?\s*/dev/null|\d*>&\d*`)
90		outputRedirectRe = regexp.MustCompile(`>\s*\S`)
91		actualDockerRe   = regexp.MustCompile(`(?im)(^|[;&|(\$]\s*)(?:/(?:usr/)?(?:local/)?bin/)?docker(\s|$)`)
92		dockerInvokeRe   = regexp.MustCompile(`(?i)(?:/(?:usr/)?(?:local/)?bin/)?docker\b.*`)
93	)
94	
95	// hasRealOutputRedirect returns true only when the command redirects output
96	// to an actual file destination (not /dev/null, not fd-to-fd like 2>&1,
97	// and not comparison operators inside quoted awk/shell strings).
98	func hasRealOutputRedirect(command string) bool {
99		s := stripQuotedStrings(command)
100		s = safeRedirectRe.ReplaceAllString(s, "")
101		return outputRedirectRe.MatchString(s)
102	}
103	
104	func hasActualDockerCommand(command string) bool {
105		return actualDockerRe.MatchString(stripQuotedStrings(command))
106	}
107	
108	func dockerInvocations(command string) []string {
109		clean := stripQuotedStrings(command)
110		var invocations []string
111		for _, line := range strings.Split(clean, "\n") {
112			for _, part := range strings.FieldsFunc(line, func(r rune) bool {
113				return r == ';' || r == '&' || r == '|'
114			}) {
115				if match := dockerInvokeRe.FindString(strings.TrimSpace(part)); match != "" {
116					invocation := strings.TrimSpace(match)
117					invocation = strings.TrimPrefix(invocation, "/usr/local/bin/")
118					invocation = strings.TrimPrefix(invocation, "/usr/bin/")
119					invocations = append(invocations, invocation)
120				}
121			}
122		}
123		return invocations
124	}
125	
126	func dockerInvocationsAllowed(command string, allowed []*regexp.Regexp) bool {
127		invocations := dockerInvocations(command)
128		if len(invocations) == 0 {
129			return true
130		}
131		for _, invocation := range invocations {
132			if !matchesAny(invocation, allowed) {
133				return false
134			}
135		}
136		return true
137	}
138	
139	func stripQuotedStrings(command string) string {
140		var b strings.Builder
141		b.Grow(len(command))
142		inSingle := false
143		inDouble := false
144		escaped := false
145		for _, r := range command {
146			switch {
147			case escaped:
148				if !inSingle && !inDouble {
149					b.WriteRune(r)
150				}
151				escaped = false
152			case r == '\\' && inDouble:
153				escaped = true
154			case r == '\'' && !inDouble:
155				inSingle = !inSingle
156			case r == '"' && !inSingle:
157				inDouble = !inDouble
158			case inSingle || inDouble:
159				// Quoted text is data or labels, not shell structure.
160			default:
161				b.WriteRune(r)
162			}
163		}
164		return b.String()
165	}
166	
167	// writePatterns identifies commands that modify state (tier 2+).
168	// Used to prevent Tier 1 execution of write operations.
169	var writePatterns = []*regexp.Regexp{
170		regexp.MustCompile(`(?i)\b(rm|mv|cp|ln|mkdir|rmdir|touch|chmod|chown|chattr)\b`),
171		regexp.MustCompile(`(?im)(^|[;&|]\s*)tee\s+(-a\s+)?/(tmp|var|volume\d+|home|root|etc|usr|lib|opt|run|mnt|btrfs)/\S+`),
172		regexp.MustCompile(`(?i)\b(sed|awk)\s+(-i|--in-place)\b`), // in-place edit
173		regexp.MustCompile(`(?im)(^|[;&|]\s*)sync(\s|$)`),
174		regexp.MustCompile(`(?i)\bsysctl\s+-w\b`),
175		regexp.MustCompile(`(?i)\bionice\b.*-c`), // ionice -c sets I/O class; plain ionice -p (read) stays tier 1
176		regexp.MustCompile(`(?i)\bdd\b.*\bof=`),  // dd writing anywhere (device/proc covered by hard-block above)
177		regexp.MustCompile(`(?i)\b(systemctl|synopkg|synoservicectl)\s+(start|stop|restart|enable|disable)\b`),
178		regexp.MustCompile(`(?im)(^|[;&|]\s*)docker\s+(start|stop|restart|rm)\b`),
179		regexp.MustCompile(`(?im)(^|[;&|]\s*)docker\s+compose\s+(restart|stop|up|pull|build)\b`),
180		regexp.MustCompile(`(?im)(^|[;&|]\s*)ssh-keygen\b`),
181		regexp.MustCompile(`(?im)(^|[;&|]\s*)kill\b`),
182		regexp.MustCompile(`(?im)(^|[;&|]\s*)pkill\b`),
183		regexp.MustCompile(`(?im)(^|[;&|]\s*)nohup\b`),
184		regexp.MustCompile(`(?im)(^|[;&|]\s*)at\b`),              // at-job scheduling
185		regexp.MustCompile(`(?im)(^|[;&|]\s*)crontab\s+-[er]\b`), // crontab edit/remove
186		// DSM WebAPI write operations (package stop/start, backup trigger, task run/enable/disable)
187		regexp.MustCompile(`(?i)SYNO\.(Core\.Package|Backup\.Task|Core\.TaskScheduler).*method=(stop|start|run|run_now|trigger|delete|enable|disable)`),
188	}
189	
190	// filePatterns identifies file-system write operations that touch user data.
191	// These require Tier 3 (approval + preview required).
192	var filePatterns = []*regexp.Regexp{
193		regexp.MustCompile(`(?i)\b(rm|mv|cp|ln|mkdir|rmdir|touch|chmod|chown|chattr)\b.*(/volume\d+/|/home/\w|/root/)`),
194		regexp.MustCompile(`(?i)\b(sed|awk)\s+(-i|--in-place)\b.*(/volume\d+/|/home/\w|/root/)`),
195		regexp.MustCompile(`(?i)\b(echo|printf|tee|cat)\b.*(>>?|\\|\\s*tee\\s+)(/volume\d+/|/home/\w|/root/)`),
196		regexp.MustCompile(`(>>?)\s*/volume`), // redirect into volume
197		regexp.MustCompile(`(>>?)\s*/home/\w`),
198		regexp.MustCompile(`(>>?)\s*/root/`),
199		regexp.MustCompile(`(?i)\brename\b.*\.old\b`),
200	}
201	
202	var (
203		allowedServiceCommands = []*regexp.Regexp{
204			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg restart SynologyDrive$`),
205			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg restart SynologyDriveShareSync$`),
206			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg restart HyperBackup$`),
207			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg status [A-Za-z0-9._-]+(?: 2>&1)?(?: \|\| .+)?$`),
208			regexp.MustCompile(`^cd /volume1/docker/synology-monitor-agent && docker compose restart$`),
209			regexp.MustCompile(`^cd /volume1/docker/synology-monitor-agent && docker compose restart nas-api$`),
210			regexp.MustCompile(`^cd /volume1/docker/synology-monitor-agent && docker compose stop$`),
211			regexp.MustCompile(`^cd /volume1/docker/synology-monitor-agent && docker compose up -d$`),
212			regexp.MustCompile(`^cd /volume1/docker/synology-monitor-agent && docker compose pull$`),
213			regexp.MustCompile(`^cd /volume1/docker/synology-monitor-agent && docker compose build --pull$`),
214		}
215	
216		allowedReadDockerCommands = []*regexp.Regexp{
217			regexp.MustCompile(`^(?:/usr/local/bin/)?docker ps(\s|$)`),
218			regexp.MustCompile(`^docker stats --no-stream`),
219			regexp.MustCompile(`^docker inspect`),
220			regexp.MustCompile(`^docker logs\b`),
221			regexp.MustCompile(`^docker port\b`),
222			regexp.MustCompile(`^docker diff\b`),
223			regexp.MustCompile(`^docker top\b`),
224			regexp.MustCompile(`(?s)^for dir in /sys/fs/cgroup/blkio/docker/\*/; do.+docker inspect`),
225		}
226	)
227	
228	// Validate checks a command against tier rules.
229	// It returns an error if the command is hard-blocked or if it
230	// requires a higher tier than what was requested.
231	func Validate(command string, requestedTier int) error {
232		if disallowedDockerCompose(command) {
233			return errors.New("docker compose command is not in the allowlist")
234		}
235	
236		// 1. Hard-block check — always fails regardless of tier
237		for _, re := range hardBlocked {
238			if re.MatchString(command) {
239				return errors.New("command is hard-blocked: " + re.String())
240			}
241		}
242	
243		if hasActualDockerCommand(command) {
244			if requestedTier == TierRead {
245				if !dockerInvocationsAllowed(command, allowedReadDockerCommands) {
246					return errors.New("docker read command is not in the allowlist")
247				}
248			} else if requestedTier >= TierService {
249				if !matchesAny(command, allowedServiceCommands) && !dockerInvocationsAllowed(command, allowedServiceCommands) {
250					return errors.New("service command is not in the allowlist")
251				}
252			}
253		}
254	
255		// 2. Tier 1: must be read-only
256		if requestedTier == TierRead {
257			for _, re := range writePatterns {
258				if re.MatchString(command) {
259					return errors.New("command requires tier 2 or higher (detected write pattern)")
260				}
261			}
262			if hasRealOutputRedirect(command) {
263				return errors.New("command requires tier 2 or higher (detected write pattern)")
264			}
265		}
266	
267		// 3. Tier 2: may be a service op but must not touch user files
268		if requestedTier == TierService {
269			if strings.Contains(command, "/volume1/") && !strings.Contains(command, "/volume1/docker/synology-monitor-agent") {
270				return errors.New("tier 2 commands may not touch user data paths")
271			}
272			for _, re := range filePatterns {
273				if re.MatchString(command) {
274					return errors.New("command touches user data and requires tier 3")
275				}
276			}
277		}
278	
279		return nil
280	}
281	
282	// ClassifyTier returns the minimum tier required for a command.
283	// The caller (web app issue agent) uses this to decide whether to
284	// auto-execute (tier 1) or prompt for approval (tier 2/3).
285	func ClassifyTier(command string) int {
286		if disallowedDockerCompose(command) {
287			return -1
288		}
289		for _, re := range hardBlocked {
290			if re.MatchString(command) {
291				return -1 // never
292			}
293		}
294		isWrite := false
295		for _, re := range writePatterns {
296			if re.MatchString(command) {
297				isWrite = true
298				break
299			}
300		}
301		if !isWrite {
302			isWrite = hasRealOutputRedirect(command)
303		}
304		if !isWrite {
305			return TierRead
306		}
307		for _, re := range filePatterns {
308			if re.MatchString(command) {
309				return TierFile
310			}
311		}
312		return TierService
313	}
314	
315	// IsHardBlocked returns true if the command can never be executed.
316	func IsHardBlocked(command string) bool {
317		if disallowedDockerCompose(command) {
318			return true
319		}
320		for _, re := range hardBlocked {
321			if re.MatchString(command) {
322				return true
323			}
324		}
325		return false
326	}
327	
328	// Summary returns a human-readable description of what a command does,
329	// used for building the approval preview shown to the operator.
330	func Summary(command string) string {
331		cmd := strings.TrimSpace(command)
332		if strings.HasPrefix(cmd, "cat ") {
333			return "Read file: " + strings.TrimPrefix(cmd, "cat ")
334		}
335		if strings.Contains(cmd, "synopkg restart") {
336			return "Restart Synology package"
337		}
338		if strings.Contains(cmd, "docker") && strings.Contains(cmd, "restart") {
339			return "Restart Docker container"
340		}
341		if strings.Contains(cmd, "mv ") && strings.Contains(cmd, ".old") {
342			return "Rename file to .old (quarantine)"
343		}
344		return cmd
345	}
346	
347	func matchesAny(command string, patterns []*regexp.Regexp) bool {
348		for _, re := range patterns {
349			if re.MatchString(command) {
350				return true
351			}
352		}
353		return false
354	}
355	
356	func disallowedDockerCompose(command string) bool {
357		cmd := strings.TrimSpace(command)
358		if !strings.Contains(cmd, "docker compose") {
359			return false
360		}
361		allowed := []string{
362			"docker compose restart",
363			"docker compose stop",
364			"docker compose up -d",
365			"docker compose pull",
366			"docker compose build --pull",
367		}
368		for _, prefix := range allowed {
369			if strings.Contains(cmd, prefix) {
370				return false
371			}
372		}
373		return true
374	}
