1	// Command server runs the NAS API HTTP service.
2	// It exposes three-tier shell execution behind a bearer-token + HMAC approval gate.
3	package main
4	
5	import (
6		"encoding/json"
7		"fmt"
8		"log"
9		"net/http"
10		"os"
11		"strings"
12		"time"
13	
14		"github.com/synology-monitor/nas-api/internal/auth"
15		"github.com/synology-monitor/nas-api/internal/executor"
16		"github.com/synology-monitor/nas-api/internal/validator"
17	)
18	
19	const (
20		maxBodyBytes     = 16 * 1024
21		maxCommandLength = 4096
22	)
23	
24	// Build-time version info — injected via -ldflags by the Dockerfile.
25	var (
26		BuildSHA  = "dev"
27		BuildTime = "unknown"
28	)
29	
30	// execRequest is the body expected on POST /exec.
31	type execRequest struct {
32		Command       string `json:"command"`
33		Tier          int    `json:"tier"`
34		TimeoutMs     int64  `json:"timeout_ms,omitempty"`     // 0 → DefaultTimeout
35		ApprovalToken string `json:"approval_token,omitempty"` // required for tier 2/3
36	}
37	
38	// previewRequest is the body expected on POST /preview.
39	type previewRequest struct {
40		Command string `json:"command"`
41	}
42	
43	// previewResponse is returned by POST /preview.
44	type previewResponse struct {
45		Tier    int    `json:"tier"`    // -1=blocked, 1=read, 2=service, 3=file
46		Summary string `json:"summary"` // human-readable description for approval UI
47		Blocked bool   `json:"blocked"`
48	}
49	
50	// errResp is returned when any request fails validation.
51	type errResp struct {
52		Error string `json:"error"`
53	}
54	
55	func main() {
56		log.SetFlags(log.Ldate | log.Ltime | log.Lshortfile)
57		log.Printf("NAS API starting… (sha=%s built=%s)", BuildSHA, BuildTime)
58	
59		apiKey := mustEnv("NAS_API_SECRET")
60		signingKey := mustEnv("NAS_API_APPROVAL_SIGNING_KEY")
61		port := envOr("NAS_API_PORT", "7734")
62	
63		v := auth.NewVerifier(apiKey, signingKey)
64	
65		mux := http.NewServeMux()
66		mux.HandleFunc("GET /health", handleHealth)
67		mux.HandleFunc("POST /exec", requireAuth(v, handleExec(v)))
68		mux.HandleFunc("POST /preview", requireAuth(v, handlePreview))
69	
70		addr := ":" + port
71		log.Printf("Listening on %s", addr)
72		server := &http.Server{
73			Addr:              addr,
74			Handler:           mux,
75			ReadHeaderTimeout: 5 * time.Second,
76			ReadTimeout:       10 * time.Second,
77			WriteTimeout:      120 * time.Second,
78			IdleTimeout:       60 * time.Second,
79		}
80		if err := server.ListenAndServe(); err != nil {
81			log.Fatalf("server: %v", err)
82		}
83	}
84	
85	// handleHealth responds with 200 OK and basic build info.
86	func handleHealth(w http.ResponseWriter, r *http.Request) {
87		writeJSON(w, http.StatusOK, map[string]string{
88			"status":     "ok",
89			"build_sha":  BuildSHA,
90			"build_time": BuildTime,
91		})
92	}
93	
94	// handleExec validates, optionally verifies an approval token, and executes the command.
95	func handleExec(v *auth.Verifier) http.HandlerFunc {
96		return func(w http.ResponseWriter, r *http.Request) {
97			r.Body = http.MaxBytesReader(w, r.Body, maxBodyBytes)
98			var req execRequest
99			if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
100				writeJSON(w, http.StatusBadRequest, errResp{"invalid JSON: " + err.Error()})
101				return
102			}
103	
104			if req.Command == "" {
105				writeJSON(w, http.StatusBadRequest, errResp{"command is required"})
106				return
107			}
108			if req.Tier < 1 || req.Tier > 3 {
109				writeJSON(w, http.StatusBadRequest, errResp{"tier must be 1, 2, or 3"})
110				return
111			}
112			if len(req.Command) > maxCommandLength {
113				writeJSON(w, http.StatusBadRequest, errResp{fmt.Sprintf("command exceeds %d bytes", maxCommandLength)})
114				return
115			}
116	
117			// Validate the command against tier rules.
118			if err := validator.Validate(req.Command, req.Tier); err != nil {
119				writeJSON(w, http.StatusForbidden, errResp{err.Error()})
120				return
121			}
122	
123			// Tier 2 and 3 require a valid approval token signed by the web app.
124			if req.Tier >= 2 {
125				if req.ApprovalToken == "" {
126					writeJSON(w, http.StatusForbidden, errResp{"approval_token required for tier 2/3"})
127					return
128				}
129				if err := v.VerifyApprovalToken(req.ApprovalToken, req.Command, req.Tier); err != nil {
130					writeJSON(w, http.StatusForbidden, errResp{err.Error()})
131					return
132				}
133			}
134	
135			timeout := time.Duration(req.TimeoutMs) * time.Millisecond
136			result := executor.Run(req.Command, timeout)
137	
138			writeJSON(w, http.StatusOK, result)
139		}
140	}
141	
142	// handlePreview classifies a command's tier and returns a human-readable summary
143	// without executing anything. Used by the web app to build the approval prompt.
144	func handlePreview(w http.ResponseWriter, r *http.Request) {
145		r.Body = http.MaxBytesReader(w, r.Body, maxBodyBytes)
146		var req previewRequest
147		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
148			writeJSON(w, http.StatusBadRequest, errResp{"invalid JSON: " + err.Error()})
149			return
150		}
151		if req.Command == "" {
152			writeJSON(w, http.StatusBadRequest, errResp{"command is required"})
153			return
154		}
155		if len(req.Command) > maxCommandLength {
156			writeJSON(w, http.StatusBadRequest, errResp{fmt.Sprintf("command exceeds %d bytes", maxCommandLength)})
157			return
158		}
159	
160		tier := validator.ClassifyTier(req.Command)
161		// On a hard-block, return WHY (actionable, and explicit that the block is
162		// permanent/stateless) instead of just echoing the command — that summary is
163		// the only signal an MCP session gets, and a bare echo is what makes sessions
164		// misread a refusal as "rate limit" / "session degradation".
165		summary := validator.Summary(req.Command)
166		if tier == -1 {
167			summary = validator.BlockExplanation(req.Command)
168		}
169		writeJSON(w, http.StatusOK, previewResponse{
170			Tier:    tier,
171			Summary: summary,
172			Blocked: tier == -1,
173		})
174	}
175	
176	// requireAuth wraps a handler with bearer-token authentication.
177	func requireAuth(v *auth.Verifier, next http.HandlerFunc) http.HandlerFunc {
178		return func(w http.ResponseWriter, r *http.Request) {
179			raw := r.Header.Get("Authorization")
180			bearer := strings.TrimPrefix(raw, "Bearer ")
181			if !v.VerifyAPIKey(bearer) {
182				writeJSON(w, http.StatusUnauthorized, errResp{"unauthorized"})
183				return
184			}
185			next(w, r)
186		}
187	}
188	
189	func writeJSON(w http.ResponseWriter, code int, v any) {
190		w.Header().Set("Content-Type", "application/json")
191		w.WriteHeader(code)
192		_ = json.NewEncoder(w).Encode(v)
193	}
194	
195	func mustEnv(key string) string {
196		v := os.Getenv(key)
197		if v == "" {
198			log.Fatalf("required env var %s is not set", key)
199		}
200		return v
201	}
202	
203	func envOr(key, fallback string) string {
204		if v := os.Getenv(key); v != "" {
205			return v
206		}
207		return fallback
208	}

